SELECT c.*, o.order_date, o.order_status_cd, m.member_email, cd_ct.code_label AS claim_type_cd_nm, cd_cs.code_label AS claim_status_cd_nm, cd_rm.code_label AS refund_method_cd_nm, cd_rc.code_label AS return_courier_cd_nm, cd_ec.code_label AS exchange_courier_cd_nm FROM od_claim c LEFT JOIN od_order o ON o.order_id = c.order_id LEFT JOIN mb_member m ON m.member_id = c.member_id LEFT JOIN sy_code cd_ct ON cd_ct.code_grp = 'CLAIM_TYPE' AND cd_ct.code_value = c.claim_type_cd LEFT JOIN sy_code cd_cs ON cd_cs.code_grp = 'CLAIM_STATUS' AND cd_cs.code_value = c.claim_status_cd LEFT JOIN sy_code cd_rm ON cd_rm.code_grp = 'REFUND_METHOD' AND cd_rm.code_value = c.refund_method_cd LEFT JOIN sy_code cd_rc ON cd_rc.code_grp = 'COURIER' AND cd_rc.code_value = c.return_courier_cd LEFT JOIN sy_code cd_ec ON cd_ec.code_grp = 'COURIER' AND cd_ec.code_value = c.exchange_courier_cd
ORDER BY c.claim_id ASC ORDER BY c.claim_id DESC ORDER BY c.member_nm ASC ORDER BY c.member_nm DESC ORDER BY c.reg_date ASC ORDER BY c.reg_date DESC ORDER BY c.request_date DESC
LIMIT #{p.limit} OFFSET #{p.offset}

