UPDATE od_claim
claim_status_cd = #{claimStatusCd}, claim_status_cd_before = #{claimStatusCdBefore}, refund_method_cd = #{refundMethodCd}, refund_amt = #{refundAmt}, refund_prod_amt = #{refundProdAmt}, refund_shipping_amt = #{refundShippingAmt}, proc_date = #{procDate}, proc_user_id = #{procUserId}, return_courier_cd = #{returnCourierCd}, return_tracking_no = #{returnTrackingNo}, return_status_cd = #{returnStatusCd}, exchange_courier_cd = #{exchangeCourierCd}, exchange_tracking_no = #{exchangeTrackingNo}, memo = #{memo}, appr_status_cd = #{apprStatusCd}, upd_by = #{updBy}, upd_date = #{updDate},
WHERE claim_id = #{claimId}
